export const EX_CATEGORIES = ['compound', 'isolation', 'plyometric', 'core', 'mobility', 'cardio'];
export const EX_MUSCLES = ['chest', 'back', 'shoulders', 'arms', 'legs', 'core', 'cardio', 'neck', 'full_body'];
export const EX_EQUIPMENT = ['barbell', 'dumbbell', 'machine', 'cable', 'bodyweight', 'kettlebell', 'band', 'other'];

function dedupeByName(lists) {
  const seen = new Set();
  const out = [];
  for (const list of lists) {
    for (const ex of list) {
      const key = ex.name.toLowerCase();
      if (seen.has(key)) continue;
      seen.add(key);
      out.push(ex);
    }
  }
  return out;
}

// The dataset (1,300+ exercises imported from exercises-dataset, see
// scripts/import_exercises_dataset.mjs) is ~0.9MB — loaded as its own chunk
// on demand rather than bundled into the main app, so app startup isn't
// slowed down by it. Cached after the first load (shared across every
// useExerciseLibrary() call in the app, so it's only fetched once).
let datasetPromise = null;
export function loadDatasetLibrary() {
  if (!datasetPromise) {
    datasetPromise = import('./exerciseLibrary.json').then((m) => m.default);
  }
  return datasetPromise;
}

/**
 * Returns the combined exercise library (built-in + dataset + user custom).
 * BASE_EXERCISES and custom exercises are available immediately; the
 * dataset's 1,300+ exercises stream in shortly after as their chunk loads.
 * Custom entries take priority over built-ins with the same name.
 * Call reload() after adding a custom exercise.
 */
export function useExerciseLibrary() {
  const [customExercises, setCustomExercises] = useState([]);
  const [datasetLibrary, setDatasetLibrary] = useState([]);

  const reload = useCallback(async () => {
    try {
      const custom = await getAllCustomExercises();
      setCustomExercises(custom.map(c => ({ ...c, custom: true })));
    } catch (e) {
      console.error('Failed to load custom exercises:', e);
    }
  }, []);

  useEffect(() => { reload(); }, [reload]);
  useEffect(() => {
    loadDatasetLibrary().then(setDatasetLibrary).catch((e) => console.error('Failed to load exercise dataset:', e));
  }, []);

  // Custom first so user additions/overrides are easy to find; de-dupe by name.
  const exercises = dedupeByName([customExercises, BASE_EXERCISES, datasetLibrary]);

  return { exercises, customExercises, reload };
}
